/// Attach `lang`'s Lexilla lexer and paint its classifications.
///
/// The single entry point every UI backend calls on a language switch.
/// Order matters and is not arbitrary:
///
/// 1. `SCI_SETILEXER` — mints a fresh `ILexer5`. Must come first;
///    everything below is instance-local state on that lexer.
/// 2. Keyword classes, so the lexer can discriminate identifiers.
/// 3. [`apply_default_styles`] — `SCI_STYLECLEARALL` propagates the
///    host's `STYLE_DEFAULT` to every slot, wiping the *previous*
///    language's colours. It has to run *after* the lexer swap and
///    *before* the per-slot colours below, or it erases them.
/// 4. The theme's own fore / italic / bold overrides.
/// 5. Fold properties — re-issued on every switch because
///    `SCI_SETILEXER` hands back an instance with `options.fold =
///    false` and Scintilla does not copy properties across instances.
/// 6. `SCI_COLOURISE` to restyle what is already on screen.
///
/// A language with no Lexilla lexer (`lexer_name()` is `None`), or one
/// whose lexer fails to construct, falls back to plain text rather than
/// leaving the previous language's lexer attached. A language with a
/// lexer but no theme row still tokenises — it just renders in
/// `STYLE_DEFAULT` until its row is added.
///
/// Callers handling User Defined Languages must route those to their
/// own container-lexer path *before* calling this; a UDL id has no
/// Lexilla lexer and would land in the plain-text fallback.
pub fn apply_lang_theme(editor: &EditorHandle, lang: LangType) {
    let Some(name) = lang.lexer_name() else {
        editor.clear_lexer();
        apply_default_styles(editor);
        editor.send(SCI_COLOURISE, 0, -1);
        return;
    };
    if !editor.set_lexer_by_name(name) {
        tracing::warn!(lexer = name, "CreateLexer returned NULL");
        editor.clear_lexer();
        apply_default_styles(editor);
        editor.send(SCI_COLOURISE, 0, -1);
        return;
    }
    if let Some(theme) = lang_theme(lang) {
        for &(class, words) in theme.keywords {
            editor.set_keywords(class, words);
        }
        apply_default_styles(editor);
        for &(style, slot) in theme.styles {
            editor.style_set_fore(style, slot_color(slot));
        }
        for &style in theme.italic {
            editor.style_set_italic(style, true);
        }
        for &style in theme.bold {
            editor.style_set_bold(style, true);
        }
    } else {
        apply_default_styles(editor);
    }
    editor.set_property("fold", "1");
    editor.set_property("fold.compact", "0");
    editor.set_property("fold.comment", "1");
    for &(name, value) in extra_fold_properties(lang) {
        editor.set_property(name, value);
    }
    editor.send(SCI_COLOURISE, 0, -1);
}

